 const { API_BASE, PORTAL_URL } = window.GanitConfig; document.addEventListener('DOMContentLoaded', () => { console.log("%cGANITSUTRAM", "color: #ff5500; font-weight: bold; font-size: 20px;"); console.log("System Architect: Jawahar R Mallah"); console.log("Organization: AITDL | aitdl.com");}); window.GanitUI = window.GanitUI || {}; window.GanitUI.theme = { init() { const savedTheme = localStorage.getItem('gs_theme') || 'dark'; this.setTheme(savedTheme); this.injectToggle(); }, setTheme(theme) { document.documentElement.setAttribute('data-theme', theme); localStorage.setItem('gs_theme', theme); const icon = theme === 'light' ? '🌙' : '☀️'; const label = theme === 'light' ? 'Midnight' : 'Gurukul'; const btn = document.getElementById('gs-theme-toggle'); if (btn) { btn.innerHTML = `<span class="theme-icon">${icon}</span> <span class="theme-label">${label}</span>`; btn.title = `Switch to ${theme === 'light' ? 'Dark' : 'Light'} Mode`; } }, toggle() { const current = document.documentElement.getAttribute('data-theme') || 'dark'; const next = current === 'dark' ? 'light' : 'dark'; this.setTheme(next); window.GanitUI.sendBeacon('theme_change', { theme: next }); }, injectToggle() { const navLinks = document.querySelector('.gs-nav-links'); if (navLinks && !document.getElementById('gs-theme-toggle')) { const toggleBtn = document.createElement('button'); toggleBtn.id = 'gs-theme-toggle'; toggleBtn.className = 'gs-nav-cta btn-ghost theme-toggle-btn'; toggleBtn.style.marginLeft = '10px'; toggleBtn.onclick = () => this.toggle(); const current = document.documentElement.getAttribute('data-theme') || 'dark'; const icon = current === 'light' ? '🌙' : '☀️'; const label = current === 'light' ? 'Midnight' : 'Gurukul'; toggleBtn.innerHTML = `<span class="theme-icon">${icon}</span> <span class="theme-label">${label}</span>`; navLinks.appendChild(toggleBtn); } }}; window.GanitUI.renderMarkdown = function (text) { if (!text) return ''; let html = text .replace(/^### (.*$)/gim, '<h3>$1</h3>') .replace(/^## (.*$)/gim, '<h2>$1</h2>') .replace(/^# (.*$)/gim, '<h1>$1</h1>') .replace(/\*\*(.*)\*\*/gim, '<b>$1</b>') .replace(/\*(.*)\*/gim, '<i>$1</i>') .replace(/\[(.*?)\]\((.*?)\)/gim, "<a href='$2' target='_blank'>$1</a>") .replace(/^\s*>\s+(.*$)/gim, '<blockquote>$1</blockquote>') .replace(/^\s*-\s+(.*$)/gim, '<ul><li>$1</li></ul>') .replace(/<\/ul>\n<ul>/gim, '') .replace(/`([^`]+)`/gim, '<code>$1</code>') .replace(/\n$/gim, '<br />'); return html.split('\n').map(line => { if (!line.match(/<(h1|h2|h3|li|ul|blockquote|br)/)) { return `<p>${line}</p>`; } return line; }).join('');}; window.GanitUI.sendBeacon = function (eventType, metadata = {}) { setTimeout(() => { if (window.GanitConfig?.ENABLE_ANALYTICS_BEACON) { fetch(`${GanitConfig.API_BASE.replace('/api', '')}/api/analytics/beacon`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ eventType, metadata }) }).catch(() => { }); } }, 10);}; window.GanitUI.gate = (function () { let selectedPersona = null; function switchScene(sceneId) { const current = document.querySelector('.gs-scene.active'); const next = document.getElementById(sceneId); if (current) current.classList.remove('active'); if (next) { next.classList.add('active'); } } return { start: () => { switchScene('gs-scene-selection'); }, select: (element) => { document.querySelectorAll('.gs-persona-card').forEach(card => card.classList.remove('selected')); element.classList.add('selected'); selectedPersona = { name: element.querySelector('h3').textContent, url: element.getAttribute('data-url') }; const btn = document.getElementById('gs-btn-proceed'); btn.classList.remove('disabled'); btn.removeAttribute('disabled'); }, proceed: () => { if (!selectedPersona) return; document.getElementById('gs-redirect-persona').textContent = selectedPersona.name; switchScene('gs-scene-redirect'); setTimeout(() => { window.location.href = selectedPersona.url; }, 2000); } };})(); window.GanitUI.pwa = (function () { let deferredPrompt; function initInstallPrompt() { window.addEventListener('beforeinstallprompt', (e) => { e.preventDefault(); deferredPrompt = e; if (localStorage.getItem('gs_install_dismissed')) { return; } setTimeout(showInstallBanner, 30000); }); window.addEventListener('appinstalled', () => { window.GanitUI.sendBeacon('app_installed', { context: 'pwa' }); hideInstallBanner(); deferredPrompt = null; }); } function showInstallBanner() { if (!deferredPrompt || document.getElementById('gs-pwa-banner')) return; const banner = document.createElement('div'); banner.id = 'gs-pwa-banner'; banner.style.cssText = ` position: fixed; bottom: 0; left: 0; width: 100%; background: var(--bg-deep, #040110); border-top: 1px solid var(--accent-soft, rgba(255,179,0,0.4)); padding: 1rem 1.5rem; display: flex; align-items: center; justify-content: space-between; z-index: 10000; font-family: var(--font-main, sans-serif); transform: translateY(100%); transition: transform 0.4s cubic-bezier(0.16, 1, 0.3, 1); color: white; box-shadow: 0 -4px 20px rgba(0,0,0,0.5); `; banner.innerHTML = ` <div style="display:flex; align-items:center; gap: 1rem;"> <div style="font-size: 1.5rem;">📱</div> <div style="font-size: 0.9rem; font-weight: 500;">Install GanitSūtram as an app</div> </div> <div style="display:flex; align-items:center; gap: 1rem;"> <button id="pwa-install-btn" style="background:var(--accent-primary, #ff5500); color:white; border:none; padding:8px 16px; border-radius:4px; font-weight:bold; cursor:pointer;">Install &rarr;</button> <button id="pwa-dismiss-btn" style="background:transparent; border:none; color:rgba(255,255,255,0.5); font-size:1.2rem; cursor:pointer;" aria-label="Dismiss">&times;</button> </div> `; document.body.appendChild(banner); requestAnimationFrame(() => { banner.style.transform = 'translateY(0)'; }); document.getElementById('pwa-install-btn').addEventListener('click', async () => { hideInstallBanner(); if (deferredPrompt) { deferredPrompt.prompt(); const { outcome } = await deferredPrompt.userChoice; if (outcome === 'accepted') { window.GanitUI.sendBeacon('pwa_install_accepted'); } else { window.GanitUI.sendBeacon('pwa_install_dismissed'); } deferredPrompt = null; } }); document.getElementById('pwa-dismiss-btn').addEventListener('click', () => { localStorage.setItem('gs_install_dismissed', '1'); window.GanitUI.sendBeacon('pwa_prompt_dismissed'); hideInstallBanner(); }); } function hideInstallBanner() { const banner = document.getElementById('gs-pwa-banner'); if (banner) { banner.style.transform = 'translateY(100%)'; setTimeout(() => banner.remove(), 400); } } return { init: initInstallPrompt };})(); window.GanitUI.injectSearchBar = function () { if (document.getElementById('gsSearchBar')) return; const searchHTML = ` <div class="gs-search-bar" id="gsSearchBar"> <input type="text" class="gs-search-input" id="gsSearchInput" placeholder="Search GanitSūtram…" autocomplete="off" aria-label="Search GanitSūtram"> <div class="gs-search-dropdown hidden" id="gsSearchDropdown"></div> </div>`; const insertTargets = [ document.querySelector('.gs-nav-actions'), document.querySelector('.gs-nav-links'), document.querySelector('nav'), document.querySelector('header') ]; for (const target of insertTargets) { if (target) { target.insertAdjacentHTML('beforeend', searchHTML); break; } } if (window.GanitSearch) { window.GanitSearch.initBar(); }}; window.GanitUI.injectBell = function () { const token = localStorage.getItem('gs_token'); if (!token) return; if (document.getElementById('gsNotifBell')) return; const bellHTML = ` <div class="gs-notif-bell" id="gsNotifBell"> <button class="gs-bell-btn" id="gsBellBtn" aria-label="Notifications" title="Notifications"> 🔔 <span class="gs-bell-badge hidden" id="gsBellBadge">0</span> </button> <div class="gs-notif-dropdown hidden" id="gsNotifDropdown"></div> </div>`; const insertTargets = [ document.querySelector('.gs-nav-actions'), document.querySelector('.gs-nav-links'), document.querySelector('nav'), document.querySelector('header') ]; for (const target of insertTargets) { if (target) { target.insertAdjacentHTML('beforeend', bellHTML); break; } } if (window.GanitNotifications) { window.GanitNotifications.init(token); window.GanitNotifications._initBell(); }}; function initCoreSystems() { if (window.GanitUI && window.GanitUI.theme) { window.GanitUI.theme.init(); } window.GanitUI.sendBeacon('page_view', { page: document.title }); window.GanitUI.pwa.init(); if (window.GanitSEO) { window.GanitSEO.init(); } if (window.GanitI18n) { const lang = localStorage.getItem('gs_locale') || 'en'; window.GanitI18n.init(lang).then(() => { window.GanitI18n.initSwitcher(); if (lang === 'hi') document.body.classList.add('font-hi'); if (lang === 'sa') document.body.classList.add('font-sa'); }); } setTimeout(() => { window.GanitUI.injectSearchBar(); window.GanitUI.injectBell(); }, 200);} if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', initCoreSystems);} else { initCoreSystems();} window.GanitUI.gate = { _selectedCard: null, nextScene() { const intro = document.getElementById('gs-scene-intro'); const selection = document.getElementById('gs-scene-selection'); if (!intro || !selection) return; intro.style.opacity = '0'; intro.style.transform = 'translateY(-20px)'; intro.style.transition = 'opacity 0.4s ease, transform 0.4s ease'; setTimeout(() => { intro.classList.remove('active'); selection.classList.add('active'); selection.style.opacity = '0'; selection.style.transform = 'translateY(20px)'; selection.style.transition = 'opacity 0.5s ease, transform 0.5s ease'; requestAnimationFrame(() => { selection.style.opacity = '1'; selection.style.transform = 'translateY(0)'; }); }, 400); }, select(card) { document.querySelectorAll('.gs-persona-card').forEach(c => { c.classList.remove('selected'); }); card.classList.add('selected'); this._selectedCard = card; const btn = document.getElementById('gs-btn-proceed'); if (btn) { btn.disabled = false; btn.classList.remove('disabled'); } }, proceed() { if (!this._selectedCard) return; const url = this._selectedCard.getAttribute('data-url'); if (!url) return; const selection = document.getElementById('gs-scene-selection'); const redirect = document.getElementById('gs-scene-redirect'); const personaLabel = document.getElementById('gs-redirect-persona'); const personaName = this._selectedCard.querySelector('h3')?.textContent || 'your path'; if (personaLabel) personaLabel.textContent = personaName; if (selection) selection.classList.remove('active'); if (redirect) redirect.classList.add('active'); setTimeout(() => { window.location.href = url; }, 900); }};